    const replaced = new Array(n).fill(false);
    let count = 0;

    for (let t = 0; t < n; t++) {
        const idx = order[t];
        replaced[idx] = true;

        // Calculate the number of valid substrings after this replacement
        let currentCount = 0;
        let prevStar = -1;

        for (let i = 0; i < n; i++) {
            if (replaced[i]) {
